Context:
- SwiftUI feature with a search input
- Users can trigger rapid sequential loads
- Goal: deterministic unidirectional state, no stale overwrites

```swift
import Foundation

enum SearchAction {
    case search(String)
    case loaded([String])
    case failed(Error)
}

struct SearchState {
    var results: [String] = []
    var isLoading = false
    var error: Error? = nil
}

@MainActor
final class SearchStore: ObservableObject {
    @Published private(set) var state = SearchState()
    private let service: SearchService

    init(service: SearchService) {
        self.service = service
    }

    func send(_ action: SearchAction) {
        switch action {
        case let .search(query):
            state.isLoading = true
            state.error = nil
            Task {
                do {
                    let results = try await service.search(query)
                    send(.loaded(results))
                } catch {
                    send(.failed(error))
                }
            }
        case let .loaded(results):
            state.isLoading = false
            state.results = results
        case let .failed(error):
            state.isLoading = false
            state.error = error
        }
    }
}
```

